/**
 * DiffEngine tests — ported from C# DiffEngineTests.cs
 */

import { describe, it, expect } from 'vitest';
import {
  computeDiff,
  computeDiffs,
  type TaskSnapshot,
  type TaskUpdate,
  ChangeFlags,
  ConstraintType,
} from '@schedulesync/engine';

function makeSnapshot(opts: Partial<TaskSnapshot> = {}): TaskSnapshot {
  return {
    uniqueId: 1,
    name: 'Task 1',
    externalKey: null,
    start: '2026-03-01T00:00:00.000Z',
    finish: '2026-03-05T00:00:00.000Z',
    durationMinutes: 2400,
    percentComplete: 0,
    constraintType: ConstraintType.ASAP as number,
    constraintDate: null,
    isSummary: false,
    isManuallyScheduled: false,
    deadline: null,
    notes: '',
    ...opts,
  };
}

function makeUpdate(opts: Partial<TaskUpdate> = {}): TaskUpdate {
  return {
    externalKey: null,
    uniqueId: null,
    name: null,
    newStart: null,
    newFinish: null,
    newDurationMinutes: null,
    newPercentComplete: null,
    newConstraintType: null,
    newConstraintDate: null,
    newDeadline: null,
    notesAppend: null,
    allowConstraintOverride: false,
    isNew: false,
    metadata: {},
    ...opts,
  };
}

describe('computeDiff', () => {
  it('no changes → flags None', () => {
    const snap = makeSnapshot();
    const update = makeUpdate({ uniqueId: 1 });
    const diff = computeDiff(snap, update);
    expect(diff.changes).toBe(ChangeFlags.None);
    expect(diff.isBlocked).toBe(false);
  });

  it('start change → flags Start', () => {
    const snap = makeSnapshot();
    const update = makeUpdate({ uniqueId: 1, newStart: '2026-03-10T00:00:00.000Z' });
    const diff = computeDiff(snap, update);
    expect(diff.changes & ChangeFlags.Start).toBeTruthy();
    expect(diff.changes & ChangeFlags.Finish).toBeFalsy();
  });

  it('finish change → flags Finish', () => {
    const snap = makeSnapshot();
    const update = makeUpdate({ uniqueId: 1, newFinish: '2026-03-20T00:00:00.000Z' });
    const diff = computeDiff(snap, update);
    expect(diff.changes & ChangeFlags.Finish).toBeTruthy();
  });

  it('duration change → flags Duration', () => {
    const snap = makeSnapshot({ durationMinutes: 100 });
    const update = makeUpdate({ uniqueId: 1, newDurationMinutes: 200 });
    const diff = computeDiff(snap, update);
    expect(diff.changes & ChangeFlags.Duration).toBeTruthy();
  });

  it('percent complete change → flags', () => {
    const snap = makeSnapshot({ percentComplete: 10 });
    const update = makeUpdate({ uniqueId: 1, newPercentComplete: 50 });
    const diff = computeDiff(snap, update);
    expect(diff.changes & ChangeFlags.PercentComplete).toBeTruthy();
  });

  it('notes append → flags Notes', () => {
    const snap = makeSnapshot();
    const update = makeUpdate({ uniqueId: 1, notesAppend: 'Updated' });
    const diff = computeDiff(snap, update);
    expect(diff.changes & ChangeFlags.Notes).toBeTruthy();
  });

  it('same values → no change flags', () => {
    const snap = makeSnapshot({
      start: '2026-03-01T00:00:00.000Z',
      finish: '2026-03-05T00:00:00.000Z',
    });
    const update = makeUpdate({
      uniqueId: 1,
      newStart: '2026-03-01T00:00:00.000Z',
      newFinish: '2026-03-05T00:00:00.000Z',
    });
    const diff = computeDiff(snap, update);
    expect(diff.changes).toBe(ChangeFlags.None);
  });

  it('summary task → blocked', () => {
    const snap = makeSnapshot({ isSummary: true });
    const update = makeUpdate({ uniqueId: 1, newStart: '2026-04-01T00:00:00.000Z' });
    const diff = computeDiff(snap, update);
    expect(diff.isBlocked).toBe(true);
  });
});

describe('computeDiffs', () => {
  it('unmatched task → blocked', () => {
    const updates: TaskUpdate[] = [
      makeUpdate({ uniqueId: 999, newStart: '2026-03-10T00:00:00.000Z' }),
    ];
    const diffs = computeDiffs(updates, () => null);
    expect(diffs).toHaveLength(1);
    expect(diffs[0].isBlocked).toBe(true);
    expect(diffs[0].before).toBeNull();
  });

  it('matching tasks → correct diffs', () => {
    const snap = makeSnapshot({ uniqueId: 1 });
    const updates: TaskUpdate[] = [
      makeUpdate({ uniqueId: 1, newStart: '2026-03-10T00:00:00.000Z' }),
    ];
    const diffs = computeDiffs(updates, (id) =>
      id === 1 ? snap : null,
    );
    expect(diffs).toHaveLength(1);
    expect(diffs[0].isBlocked).toBe(false);
    expect(diffs[0].changes & ChangeFlags.Start).toBeTruthy();
  });

  it('duration within tolerance (0.001) → no change', () => {
    const snap = makeSnapshot({ durationMinutes: 100.0 });
    const update = makeUpdate({ uniqueId: 1, newDurationMinutes: 100.0005 });
    const diff = computeDiff(snap, update);
    expect(diff.changes & ChangeFlags.Duration).toBeFalsy();
  });
});
